import React from 'react'
import BlogPreview from './BlogPreview.jsx';
import {useEffect} from 'react'
const BlogList = () => {
  useEffect(()=>{
    fetch('/blog').then(response=>{
      response.json().then(posts=>{
        console.log(posts)
      })
    })
  },[])
  return (
    <div>
      <BlogPreview></BlogPreview>
    </div>
  )
}

export default BlogList
